2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_RATE = 0.1;
5	const CURSED_SURCHARGE_RATE = 0.5;
6	
7	const MAIN_ITEM_BASE_PREMIUM_BY_TYPE: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	const COMPONENT_TYPES = new Set<string>(["rune", "moonstone"]);
15	const COMPONENT_BASE_PREMIUM = 25;
16	const COMPONENT_BLOCK_PREMIUM = 60;
17	
18	export type Customer = {
19	  yearsInsured: number;
20	  previousQuotes: number;
21	};
22	
23	export type Item = {
24	  type: string;
25	  material?: string;
26	  enchantment?: number;
27	  cursed?: boolean;
28	};
29	
30	export type QuoteInput = {
31	  items: Item[];
32	  customer: Customer;
33	};
34	
35	const BLOCK_SIZE = 3;
36	
37	const formsOneBlock = (count: number): boolean => {
38	  if (count < BLOCK_SIZE) return false;
39	  const leftover = count - BLOCK_SIZE;
40	  return leftover !== 1;
41	};
42	
43	const componentGroupBase = (count: number): number => {
44	  const blocks = formsOneBlock(count) ? 1 : 0;
45	  const singles = count - blocks * BLOCK_SIZE;
46	  return blocks * COMPONENT_BLOCK_PREMIUM + singles * COMPONENT_BASE_PREMIUM;
47	};
48	
49	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
50	
51	const mainItemBase = (item: Item): number =>
52	  MAIN_ITEM_BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
53	
54	const basePremium = (items: Item[]): number => {
55	  const componentCounts: Record<string, number> = {};
56	  let mainTotal = 0;
57	  for (const item of items) {
58	    if (isComponent(item)) {
59	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
60	    } else {
61	      mainTotal += mainItemBase(item);
62	    }
63	  }
64	  const componentTotal = Object.values(componentCounts).reduce(
65	    (sum, count) => sum + componentGroupBase(count),
66	    0
67	  );
68	  return mainTotal + componentTotal;
69	};
70	
71	const itemSurcharges = (items: Item[]): number => {
72	  let total = 0;
73	  for (const item of items) {
74	    if (isComponent(item)) continue;
75	    if (item.cursed) total += mainItemBase(item) * CURSED_SURCHARGE_RATE;
76	  }
77	  return total;
78	};
79	
80	const roundUpToGold = (amount: number): number => {
81	  const precisionSafe = Math.round(amount * 100) / 100;
82	  return Math.ceil(precisionSafe);
83	};
84	
85	export const quote = (input: QuoteInput): number => {
86	  const base = basePremium(input.items);
87	  const surcharges = itemSurcharges(input.items);
88	  const firstInsurance = base * FIRST_INSURANCE_RATE;
89	  const total = base + surcharges + firstInsurance + PROCESSING_FEE;
90	  return roundUpToGold(total);
91	};
